class AIModelService {
  /**
   * 根据任务类型选择最优模型
   */
  selectModel(taskType: TaskType): AIModel {
    return ModelTaskMapping[taskType] || 'doubao-pro'
  }

  /**
   * 获取模型配置
   */
  getModelConfig(model: AIModel): ModelConfig {
    return ModelConfigs[model] || ModelConfigs['doubao-pro']
  }

  /**
   * 调用 AI 模型 (非流式)
   */
  async call(
    taskType: TaskType,
    prompt: string,
    options?: Partial<ModelConfig> & { systemPrompt?: string }
  ): Promise<{ success: boolean; content?: string; error?: string }> {
    try {
      const model = this.selectModel(taskType)
      const config = { ...this.getModelConfig(model), ...options }

      const result = await window.electronAPI.ai.call(prompt, {
        model,
        ...config,
        systemPrompt: options?.systemPrompt,
      })

      return result
    } catch (error: unknown) {
      const msg = error instanceof Error ? error.message : String(error)
      return { success: false, error: msg }
    }
  }

  /**
   * 流式调用 AI 模型
   */
  async stream(
    taskType: TaskType,
    prompt: string,
    onChunk: (chunk: string, done: boolean) => void,
    onError?: (error: string) => void,
    options?: Partial<ModelConfig> & { systemPrompt?: string }
  ): Promise<void> {
    let removeChunkListener = () => {}
    let removeErrorListener = () => {}

    try {
      const model = this.selectModel(taskType)
      const config = { ...this.getModelConfig(model), ...options }

      // 监听流式输出
      removeChunkListener = window.electronAPI.ai.onStreamChunk((chunk) => {
        if (chunk.done) {
          onChunk('', true)
          removeChunkListener()
          removeErrorListener()
        } else {
          onChunk(chunk.content, false)
        }
      })

      // 监听错误
      removeErrorListener = window.electronAPI.ai.onStreamError((error) => {
        if (onError) onError(error)
        removeChunkListener()
        removeErrorListener()
      })

      // 发起流式请求
      await window.electronAPI.ai.stream(prompt, {
        model,
        ...config,
        systemPrompt: options?.systemPrompt,
      })
    } catch (error: unknown) {
      const msg = error instanceof Error ? error.message : String(error)
      if (onError) onError(msg)
    }
  }

  /**
   * 测试模型连接
   */
  async testConnection(model: AIModel): Promise<boolean> {
    try {
      const result = await window.electronAPI.ai.testConnection(model)
      if (!result || typeof result !== 'object') return false
      return !!(result.success && result.result)
    } catch {
      return false
    }
  }
}

